// Use a data-driven task: asyncAwait runs the callback only after all futures complete
asyncAwait(futures, () -> {
    System.out.println("Aggregating Results");
    // safeGet() is safe here since asyncAwait guarantees all futures are resolved
    List<User> allUsers = futures.stream()
        .map(HjFuture::safeGet)
        .filter(users -> users != null)
        .flatMap(List::stream)
        .collect(Collectors.toList());

    // Aggregate contributions per user using streams
    Map<String, Integer> aggregatedMap = allUsers.stream()
        .collect(Collectors.groupingBy(
            u -> u.login,
            Collectors.summingInt(u -> u.contributions)
        ));

    // Convert to sorted list of Users (descending contributions)
    List<User> aggregatedUsers = aggregatedMap.entrySet().stream()
        .map(entry -> new User(entry.getKey(), entry.getValue()))
        .sorted((o1, o2) -> o2.contributions - o1.contributions)
        .collect(Collectors.toList());

    System.out.println("Displaying Results");
    updateContributors(aggregatedUsers);
